package com.sigi.configuration.cache;

import com.github.benmanes.caffeine.cache.Caffeine;
import org.springframework.cache.CacheManager;
import org.springframework.cache.caffeine.CaffeineCacheManager;
import org.springframework.cache.annotation.EnableCaching;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import static com.sigi.util.Constants.*;

import java.util.concurrent.TimeUnit;

@Configuration
@EnableCaching
public class CacheConfig {

    @Bean
    public CacheManager cacheManager() {
        CaffeineCacheManager cacheManager = new CaffeineCacheManager(
                CLIENT_BY_ID, CLIENTS_BY_NAME, CLIENT_BY_IDENTIFICATION, ALL_ACTIVE_CLIENTS, ALL_DELETED_CLIENTS, CLIENTS_DELETED_BY_NAME,
                DISPATCHER_BY_ID, DISPATCHER_BY_NAME, ALL_ACTIVE_DISPATCHERS, DISPATCHERS_DELETED_BY_NAME, ALL_DELETED_DISPATCHERS,
                PRODUCT_BY_ID, PRODUCT_BY_SKU, PRODUCTS_BY_NAME, PRODUCTS_BY_CATEGORY, PRODUCTS_BY_PRICE_RANGE, ALL_ACTIVE_PRODUCTS, ALL_DELETED_PRODUCTS, PRODUCTS_DELETED_BY_NAME,
                MOVEMENTS_BY_PRODUCT, MOVEMENTS_BY_ORDER, MOVEMENTS_BY_DISPATCHER, MOVEMENTS_BY_TYPE, ALL_ACTIVE_MOVEMENTS, ALL_DELETED_MOVEMENTS, MOVEMENTS_DELETED_BY_TYPE, MOVEMENT_BY_ID,
                WAREHOUSE_BY_ID, WAREHOUSES_ACTIVE, WAREHOUSES_BY_CAPACITY, ALL_DELETED_WAREHOUSES, WAREHOUSES_DELETED_BY_NAME,WAREHOUSE_NAME,
                ORDER_BY_ID, ORDER_CALCULATE, ORDERS_BY_CLIENT, ORDERS_BY_USER, ALL_ACTIVE_ORDERS, ALL_DELETED_ORDERS,
                LINE_ORDERS_BY_ORDER, ALL_ACTIVE_LINE_ORDERS, ALL_DELETED_LINE_ORDERS, LINE_ORDERS_BY_PRODUCT, LINE_ORDERS_DELETED_BY_PRODUCT,LINE_ORDER_BY_ID,
                INVENTORY_BY_ID, INVENTORY_BY_PRODUCT_WAREHOUSE, INVENTORIES_BY_PRODUCT, INVENTORIES_BY_WAREHOUSE, INVENTORIES_BY_LOW_STOCK, INVENTORIES_BY_AVAILABLE_PRODUCT, ALL_ACTIVE_INVENTORIES, ALL_DELETED_INVENTORIES, INVENTORIES_DELETED_BY_NAME,
                USER_BY_ID, USER_BY_EMAIL, USERS_ACTIVE, USERS_INACTIVE, USER_PROFILE, USERS_INACTIVE_BY_NAME,
                NOTIFICATION_BY_ID, NOTIFICATIONS_BY_USER, NOTIFICATIONS_UNREAD, NOTIFICATIONS_BY_TYPE, NOTIFICATIONS_BY_SEVERITY, NOTIFICATIONS_COUNT_UNREAD,
                CHAT_MESSAGE_BY_ROOM, CHAT_MESSAGE_BY_SENDER, CHAT_MESSAGE_BY_TYPE, CHAT_MESSAGE_COUNT_UNREAD,
                CHAT_ROOMS_BY_USER, CHAT_ROOM_BY_ID,
                INVOICE_BY_ID, ALL_ACTIVE_INVOICES, INVOICES_BY_CLIENT, INVOICES_BY_STATUS, INVOICE_BY_NUMBER, INVENTORIES_DELETED_BY_NAME, ALL_DELETED_INVOICES,
                METRICS
        );

        cacheManager.setCaffeine(Caffeine.newBuilder()
                .expireAfterWrite(10, TimeUnit.MINUTES)
                .maximumSize(1000)
                .recordStats());

        return cacheManager;
    }
}
